ALTER TABLE contacts ADD COLUMN IF NOT EXISTS delete_batch_id VARCHAR(36) DEFAULT NULL;
ALTER TABLE contacts ADD INDEX IF NOT EXISTS idx_contacts_delete_batch (delete_batch_id);

ALTER TABLE companies ADD COLUMN IF NOT EXISTS delete_reason TEXT DEFAULT NULL;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS delete_batch_id VARCHAR(36) DEFAULT NULL;
ALTER TABLE companies ADD INDEX IF NOT EXISTS idx_companies_delete_batch (delete_batch_id);

ALTER TABLE deals ADD COLUMN IF NOT EXISTS delete_reason TEXT DEFAULT NULL;
ALTER TABLE deals ADD COLUMN IF NOT EXISTS delete_batch_id VARCHAR(36) DEFAULT NULL;

ALTER TABLE tasks ADD COLUMN IF NOT EXISTS delete_reason TEXT DEFAULT NULL;
ALTER TABLE tasks ADD COLUMN IF NOT EXISTS delete_batch_id VARCHAR(36) DEFAULT NULL;

CREATE TABLE IF NOT EXISTS delete_batches (
  id VARCHAR(36) NOT NULL PRIMARY KEY,
  tenant_company_id INT NOT NULL,
  requested_by_id INT NOT NULL,
  requested_by_name VARCHAR(255) NOT NULL,
  scope ENUM('contacts','companies','all') NOT NULL,
  reason TEXT NOT NULL,
  status ENUM('pending','purged','restored') NOT NULL DEFAULT 'pending',
  estimated_count INT NOT NULL DEFAULT 0,
  actual_count INT DEFAULT NULL,
  created_at BIGINT NOT NULL,
  resolved_at BIGINT DEFAULT NULL,
  admin_note TEXT DEFAULT NULL,
  INDEX idx_db_tenant (tenant_company_id),
  INDEX idx_db_status (status)
);

